359	// =============================================================================
360	// Production code — data types and logic
361	// =============================================================================
362	
363	/// <summary>A single parsed log entry.</summary>
364	record LogEntry(string Level, string Message, DateTime Timestamp, string Host);
365	
366	/// <summary>An aggregated frequency record for a specific error/warning type.</summary>
367	record FrequencyRecord(string Level, string Message, int Count, DateTime FirstOccurrence, DateTime LastOccurrence);
368	
369	/// <summary>Parses raw log lines in syslog or JSON format.</summary>
370	static class LogParser
371	{
372	    // Syslog format: "YYYY-MM-DD HH:MM:SS hostname facility LEVEL: message"
373	    // JSON format: {"timestamp":"...","host":"...","level":"...","message":"..."}
374	    public static LogEntry? ParseLine(string line)
375	    {
376	        if (string.IsNullOrWhiteSpace(line))
377	            return null;
378	
379	        var trimmed = line.Trim();
380	
381	        // Try JSON first if it starts with '{'
382	        if (trimmed.StartsWith('{'))
383	            return TryParseJson(trimmed);
384	
385	        // Otherwise try syslog format
386	        return TryParseSyslog(trimmed);
387	    }
388	
389	    /// <summary>Parse all lines, skipping any that fail to parse.</summary>
390	    public static IEnumerable<LogEntry> ParseLines(IEnumerable<string> lines)
391	    {
392	        foreach (var line in lines)
393	        {
394	            var entry = ParseLine(line);
395	            if (entry is not null)
396	                yield return entry;
397	        }
398	    }
399	
400	    /// <summary>Normalize level to uppercase and map WARN → WARNING.</summary>
401	    private static string NormalizeLevel(string level)
402	    {
403	        var upper = level.ToUpperInvariant();
404	        return upper == "WARN" ? "WARNING" : upper;
405	    }
406	
407	    private static LogEntry? TryParseSyslog(string line)
408	    {
409	        // Expected: "2024-01-15 08:23:01 server1 syslog ERROR: Disk space critically low"
410	        // Parts:     ^--- timestamp ---^ ^host^  ^fac^  ^level^: ^--- message ---^
411	        // The timestamp is 19 chars: "YYYY-MM-DD HH:MM:SS"
412	        if (line.Length < 20)
413	            return null;
414	
415	        if (!DateTime.TryParse(line[..19], out var timestamp))
416	            return null;
417	
418	        // After timestamp, split remaining by spaces to get host, facility, level
419	        var rest = line[20..];
420	        var colonIdx = rest.IndexOf(':');
421	        if (colonIdx < 0)
422	            return null;
423	
424	        var beforeColon = rest[..colonIdx].Split(' ', StringSplitOptions.RemoveEmptyEntries);
425	        if (beforeColon.Length < 3)
426	            return null;
427	
428	        var host = beforeColon[0];
429	        // facility is beforeColon[1] (e.g. "syslog") — we don't need it
430	        var level = NormalizeLevel(beforeColon[^1]); // last word before colon is the level
431	        var message = rest[(colonIdx + 1)..].Trim();
432	
433	        return new LogEntry(level, message, timestamp, host);
434	    }
435	
436	    private static LogEntry? TryParseJson(string line)
437	    {
438	        try
439	        {
440	            using var doc = JsonDocument.Parse(line);
441	            var root = doc.RootElement;
442	
443	            var level = NormalizeLevel(root.GetProperty("level").GetString() ?? "");
444	            var message = root.GetProperty("message").GetString() ?? "";
445	            var host = root.TryGetProperty("host", out var h) ? h.GetString() ?? "" : "";
446	
447	            DateTime timestamp;
448	            var tsStr = root.GetProperty("timestamp").GetString();
449	            if (tsStr is null || !DateTime.TryParse(tsStr, null,
450	                    System.Globalization.DateTimeStyles.AdjustToUniversal |
451	                    System.Globalization.DateTimeStyles.AssumeUniversal,
452	                    out timestamp))
453	                return null;
454	
455	            return new LogEntry(level, message, timestamp, host);
456	        }
457	        catch
458	        {
459	            return null;
460	        }
461	    }
462	}
463	
464	/// <summary>Filtering and aggregation logic for log entries.</summary>
465	static class LogAnalyzer
466	{
467	    /// <summary>Keep only ERROR and WARNING entries.</summary>
468	    public static IEnumerable<LogEntry> FilterErrorsAndWarnings(IEnumerable<LogEntry> entries)
469	        => entries.Where(e => e.Level is "ERROR" or "WARNING");
470	
471	    /// <summary>
472	    /// Build a frequency table grouped by (level, message).
473	    /// Tracks count, first occurrence, and last occurrence for each group.
474	    /// Results are sorted by count descending.
475	    /// </summary>
476	    public static List<FrequencyRecord> BuildFrequencyTable(IEnumerable<LogEntry> entries)
477	    {
478	        return entries
479	            .GroupBy(e => (e.Level, e.Message))
480	            .Select(g => new FrequencyRecord(
481	                g.Key.Level,
482	                g.Key.Message,
483	                g.Count(),
484	                g.Min(e => e.Timestamp),
485	                g.Max(e => e.Timestamp)))
486	            .OrderByDescending(r => r.Count)
487	            .ThenBy(r => r.FirstOccurrence)
488	            .ToList();
489	    }
490	}
491	
492	/// <summary>Formats frequency table data as human-readable text or JSON.</summary>
493	static class ReportFormatter
494	{
495	    /// <summary>Format as an aligned, human-readable table.</summary>
496	    public static string FormatTable(List<FrequencyRecord> records)
497	    {
498	        if (records.Count == 0)
499	            return "No error or warning entries found.";
500	
501	        // Compute column widths
502	        var levelWidth = Math.Max("Level".Length, records.Max(r => r.Level.Length));
503	        var msgWidth = Math.Max("Message".Length, records.Max(r => r.Message.Length));
504	        var countWidth = Math.Max("Count".Length, records.Max(r => r.Count.ToString().Length));
505	        const int tsWidth = 19; // "yyyy-MM-dd HH:mm:ss"
506	        const string tsFmt = "yyyy-MM-dd HH:mm:ss";
507	
508	        var sb = new System.Text.StringBuilder();
509	
510	        // Header
511	        sb.AppendLine($"{"Level".PadRight(levelWidth)}  {"Count".PadLeft(countWidth)}  {"Message".PadRight(msgWidth)}  {"First Occurrence".PadRight(tsWidth)}  {"Last Occurrence".PadRight(tsWidth)}");
512	        sb.AppendLine($"{new string('-', levelWidth)}  {new string('-', countWidth)}  {new string('-', msgWidth)}  {new string('-', tsWidth)}  {new string('-', tsWidth)}");
513	
514	        foreach (var r in records)
515	        {
516	            sb.AppendLine($"{r.Level.PadRight(levelWidth)}  {r.Count.ToString().PadLeft(countWidth)}  {r.Message.PadRight(msgWidth)}  {r.FirstOccurrence.ToString(tsFmt)}  {r.LastOccurrence.ToString(tsFmt)}");
517	        }
518	
519	        sb.AppendLine();
520	        sb.AppendLine($"Total distinct error/warning types: {records.Count}");
521	        sb.AppendLine($"Total occurrences: {records.Sum(r => r.Count)}");
522	
523	        return sb.ToString();
524	    }
525	
526	    /// <summary>Format as a JSON array using Utf8JsonWriter (AOT-compatible).</summary>
527	    public static string FormatJson(List<FrequencyRecord> records)
528	    {
529	        using var stream = new System.IO.MemoryStream();
530	        using var writer = new Utf8JsonWriter(stream, new JsonWriterOptions { Indented = true });
531	
532	        writer.WriteStartArray();
533	        foreach (var r in records)
534	        {
535	            writer.WriteStartObject();
536	            writer.WriteString("level", r.Level);
537	            writer.WriteString("message", r.Message);
538	            writer.WriteNumber("count", r.Count);
539	            writer.WriteString("first_occurrence", r.FirstOccurrence.ToString("yyyy-MM-ddTHH:mm:ssZ"));
540	            writer.WriteString("last_occurrence", r.LastOccurrence.ToString("yyyy-MM-ddTHH:mm:ssZ"));
541	            writer.WriteEndObject();
542	        }
543	        writer.WriteEndArray();
544	        writer.Flush();
545	
546	        return System.Text.Encoding.UTF8.GetString(stream.ToArray());
547	    }
548	}
